        Assert.Equal(ds.UtcTimes.Sunrise,  Fmt(schedule.GetPrayer(PrayerType.Sunrise)!.Value.DateTime));
        Assert.Equal(ds.UtcTimes.Dhuhr,   Fmt(schedule.GetPrayer(PrayerType.Dhuhr)!.Value.DateTime));
        Assert.Equal(ds.UtcTimes.Asr,     Fmt(schedule.GetPrayer(PrayerType.Asr)!.Value.DateTime));
        Assert.Equal(ds.UtcTimes.Maghrib, Fmt(schedule.GetPrayer(PrayerType.Maghrib)!.Value.DateTime));
        Assert.Equal(ds.UtcTimes.Isha,    Fmt(schedule.GetPrayer(PrayerType.Isha)!.Value.DateTime));
