    // ── Oracle: Reykjavik 2026-01-15 (high-latitude rule active) ──────────

    [Fact]
    public async Task Oracle_Reykjavik_2026_01_15_MatchesAllPrayers()
    {
        var ds = LoadDataset("reykjavik-2026-01-15.json");
